import{_ as e,o as l,c as a,ae as t}from"./chunks/framework.DIepHV_Q.js";const p=JSON.parse('{"title":"简介","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/index.md","filePath":"zh/guide/index.md"}'),n={name:"zh/guide/index.md"};function o(r,i,s,d,h,u){return l(),a("div",null,[...i[0]||(i[0]=[t('<h1 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h1><h2 id="这是什么" tabindex="-1">这是什么？ <a class="header-anchor" href="#这是什么" aria-label="Permalink to &quot;这是什么？&quot;">​</a></h2><p><code>vite-plugin-svg-icons-ng</code> 是一个专为 Vite 打造的高性能 SVG 图标插件。 它会从本地 SVG 文件自动生成 SVG 精灵，并在运行时完成注入，让你可以像使用普通图标一样高效地使用 SVG。 无需手动维护 sprite，无需额外请求，也无需复杂配置，即可构建一套统一、可复用的图标系统。</p><blockquote><p>本项目受到 vite-plugin-svg-icons 的启发，在此致谢。</p></blockquote><h2 id="为什么选择它" tabindex="-1">为什么选择它？ <a class="header-anchor" href="#为什么选择它" aria-label="Permalink to &quot;为什么选择它？&quot;">​</a></h2><h4 id="在实际开发中-使用-svg-图标往往会遇到这些问题" tabindex="-1">在实际开发中，使用 SVG 图标往往会遇到这些问题： <a class="header-anchor" href="#在实际开发中-使用-svg-图标往往会遇到这些问题" aria-label="Permalink to &quot;在实际开发中，使用 SVG 图标往往会遇到这些问题：&quot;">​</a></h4><ul><li>需要手动管理图标文件、手动导入、手写路径</li><li><code>&lt;img src&gt;</code> 或 inline SVG 使用繁琐，难以复用</li><li>响应式 / 颜色控制不自然，维护成本高</li><li>图标更新流程复杂，影响开发效率</li><li>dev / build / SSR 行为不一致，容易踩坑</li></ul><h4 id="vite-plugin-svg-icons-ng-解决了这些问题" tabindex="-1">vite-plugin-svg-icons-ng 解决了这些问题： <a class="header-anchor" href="#vite-plugin-svg-icons-ng-解决了这些问题" aria-label="Permalink to &quot;vite-plugin-svg-icons-ng 解决了这些问题：&quot;">​</a></h4><ul><li>从文件自动生成 SVG 精灵，无需手动导入</li><li>统一通过 <code>&lt;use&gt;</code> 使用图标，天然支持样式控制</li><li>内置 HMR，图标修改即时生效</li><li>跨 dev / build / SSR 保持一致输出</li><li>无额外请求，性能更优</li></ul><p>让图标从“需要管理的资源”，变成“可以直接使用的能力”。</p><h2 id="特性" tabindex="-1">特性 <a class="header-anchor" href="#特性" aria-label="Permalink to &quot;特性&quot;">​</a></h2><ul><li><p>🚀 预生成与自动注入<br> 自动从文件生成 SVG 精灵，并在运行时完成注入，一次挂载即可全局复用。</p></li><li><p>⚡ 高性能<br> 异步构建结合缓存优化，仅在必要时更新图标，带来更快、更流畅的开发与运行体验。</p></li><li><p>🔥 HMR 开发体验 图标变更后会快速生效，流畅刷新，让开发过程更加顺畅高效。</p></li><li><p>🧩 SSR 支持<br> 天然兼容 SSR 场景，确保服务端与客户端渲染一致，无需额外配置。</p></li><li><p>🧱 跨环境一致性<br> 在开发、构建与 SSR 场景下保持一致的 SVG 精灵输出，避免环境差异带来的问题。</p></li><li><p>📦 开箱即用<br> 提供合理默认配置与完善文档，快速接入，轻松构建统一的图标系统。</p></li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li>从 <a href="/vite-plugin-svg-icons-ng/zh/guide/quick-start.html">快速开始</a> 开始</li><li>选项细节见 <a href="/vite-plugin-svg-icons-ng/zh/guide/options.html">插件选项</a></li></ul>',14)])])}const g=e(n,[["render",o]]);export{p as __pageData,g as default};
